#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


/*
vUv *=2 ;
vec2 m = floor(fract(vUv*0.5)*2);
vUv = fract(vUv)*(1-m) + (m)*fract(1-vUv);
*/
vec2 trans=1+.3*vec2(roam_sin.x,roam_cos.y);
vec2 move=vec2(.12*uTime+.18*roam_sin.x, .12*uTime+.18*roam_cos.y);
/*
trans *=2 ;
m = floor(fract(trans*0.5)*2);
trans = fract(trans)*(1-m) + (m)*fract(1-trans);

move *=2 ;
m = floor(fract(move*0.5)*2);
move = fract(move)*(1-m) + (m)*fract(1-move);
*/

vec3 uv_sphere;
uv_sphere.xy = vUv*trans+move;
uv_sphere.xy = fract( uv_sphere.xy  ) * 2.0;
uv_sphere.xy = 1.0 - abs( uv_sphere.xy - 1.0 );
uv_sphere = textureBias( sampler_rand00, vec4(uv_sphere.xy,0.0,-0.5) );
ret = uv_sphere;

ret= uv_sphere;//texture(sampler_rand00,vUv*trans+move);
ret.x*=sin(vAngle*8+.31*uTime)*.3;
ret.y*=.5+sin(vAngle*4+.21*uTime)*.3;
ret.z*=.5+sin(vRadius*2+.4*uTime)*.3;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    ret = texture(sampler_main, vUv).xyz;

    ret *= 0.6;

    // LSB accentuate effect: (LSB = least significant bit)
    vec3 d = vec3(uTexSize.zw, 0)*1.0;
    float b1 = lum(GetPixel(vUv + d.xz));
    float b2 = lum(GetPixel(vUv - d.xz));
    float b3 = lum(GetPixel(vUv + d.zy));
    float b4 = lum(GetPixel(vUv - d.zy));
    vec2 c = vec2(b1-b2,b3-b4);
    c = fract(c*20);
    c = clamp01((c-0.5)*999)*2-1;
    c = mix(c, 0, clamp01( lum(GetBlur2(vUv))*30-17 ));
    ret += 0.104*c.x;
    ret += 0.104*c.y;

    ret = mix(ret, lum(ret), -1);


  fragColor = ret;
}
